-- 4.3.3 Группа онлайн мониторинга операций клиентов
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.3.3'
  FROM (VALUES
    ('Обеспечение своевременного выявления и квалификации операций (сделок) клиентов – юридических лиц и индивидуальных предпринимателей, связанных с легализацией (отмыванием) доходов, полученных преступным путём, или финансированием терроризма, в том числе при осуществлении Банком профессиональной деятельности на рынке ценных бумаг','control'),
    ('Разработка программ и процедур, направленных на выявление и предотвращение необычных операций (сделок), выявлении совокупности подозрительных операций и (или) действий, в том числе при осуществлении Банком профессиональной деятельности на рынке ценных бумаг, которые могут привести к потере Банком своей деловой репутации или иным правовым и финансовым рискам, в части, касающейся деятельности Группы онлайн мониторинга операций клиентов','methodology'),
    ('Осуществление выявления новых типов сомнительных финансовых схем, направленных на легализацию преступных доходов, или финансирование терроризма, в части, касающейся деятельности Группы онлайн мониторинга операций клиентов','analytical'),
    ('Разработка технических заданий для реализации Управлением систем комплаенс-контроля и управления рисками Департамента развития общебанковских систем по вопросам, входящим в компетенцию Группы онлайн мониторинга операций клиентов','methodology'),
    ('Осуществление онлайн согласования платежей клиентов Банка с признаками сомнительности','control'),
    ('Сопровождение проверок Банка России, внутреннего аудита Банка в части, касающейся деятельности компетенции Группы онлайн мониторинга операций клиентов','control'),
    ('Подготовка ответов на обращения государственных органов (ФНС, МВД и прочие) в части, касающейся деятельности компетенции Группы онлайн мониторинга операций клиентов','communication'),
    ('Осуществление рассмотрения обращений структурных бизнес-подразделений Банка по согласованию индивидуальных тарифов клиентам Банка в целях минимизации риска проведения подозрительных операций (сделок) в части, касающейся компетенции Группы онлайн мониторинга операций клиентов','control'),
    ('Обеспечение подготовки и направления в адрес клиентов ответов на их обращения, связанные с выполнением деятельности Подразделения, в части, касающейся компетенции Группы онлайн мониторинга операций клиентов','communication'),
    ('Осуществление консультирования работников УФМ СЦ по вопросам формирования сообщений о подозрительных операциях в целях обеспечения неукоснительного соблюдения ими требований законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','communication'),
    ('Взаимодействие с другими структурными подразделениями Банка по любым вопросам в рамках Федерального закона № 115-ФЗ, в части, касающейся компетенции Группы онлайн мониторинга операций клиентов','communication'),
    ('Получение информации об отнесении клиентов – юридических лиц и индивидуальных предпринимателей к группам риска совершения подозрительных операций через личный кабинет Банка России в соответствии с абзацем вторым п. 1 ст. 7.6 Федерального закона № 115-ФЗ','operational'),
    ('В части, касающейся деятельности Подразделения, реализация применения, отмены и обжалования мер, предусмотренных п. 5 ст. 7.7 Федерального закона № 115-ФЗ по клиентам с высокой степенью (уровнем) риска, в отношении которых Банк ограничивает операции (не проводит списание, не осуществляет переводы, в том числе через СБП, не выдаёт наличные, не выдаёт остаток при расторжении договора, прекращает возможность использования электронного средства платежа)','control')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.3.3' AND u.is_archived = false;